<div class="preloader" *ngIf="isLoading">
    <div class="loader-ripple">
        <div></div>
        <div></div>
    </div>
</div>
<!-- preloader end -->

<!-- Toast Container -->
<div class="toast-container position-fixed top-0 end-0 p-3">
  <div *ngFor="let toast of toasts; let i = index" class="toast" [ngClass]="toast.type" role="alert" aria-live="assertive" aria-atomic="true">
    <div class="toast-header">
      <strong class="me-auto">{{ toast.title }}</strong>
      <button type="button" class="btn-close" (click)="removeToast(i)" aria-label="Close"></button>
    </div>
    <div class="toast-body">
      {{ toast.message }}
    </div>
  </div>
</div>

<!-- Register Form Area -->
<div class="auth-area py-120">
  <div class="container">
    <div class="col-md-5 mx-auto">
      <div class="auth-form">
        <div class="auth-header">
          <img src="assets/img/logo/logo arabsoft.png" alt="Logo">
          <p>Create your free lovcare account</p>
        </div>
        <form [formGroup]="registerForm" (ngSubmit)="onSubmit()">
          <div class="form-group">
            <div class="form-icon">
              <i class="far fa-user-tie"></i>
              <input type="text" formControlName="firstName" class="form-control" placeholder="First Name" (blur)="validateField('firstName')" />
            </div>
          </div>
          <div class="form-group">
            <div class="form-icon">
              <i class="far fa-user-tie"></i>
              <input type="text" formControlName="lastName" class="form-control" placeholder="Last Name" (blur)="validateField('lastName')" />
            </div>
          </div>
          <div class="form-group">
            <div class="form-icon">
              <i class="far fa-envelope"></i>
              <input type="email" formControlName="email" class="form-control" placeholder="Your Email" (blur)="validateField('email')" />
            </div>
          </div>
          <div class="form-group">
            <div class="form-icon">
              <i class="far fa-key"></i>
              <input [type]="showPassword ? 'text' : 'password'" formControlName="password" class="form-control" placeholder="Your Password" (input)="updatePasswordStrength()" (blur)="validateField('password')" />
              <span class="password-view" (click)="togglePasswordVisibility()">
                <i [class]="showPassword ? 'far fa-eye' : 'far fa-eye-slash'"></i>
              </span>
            </div>
            <div class="password-strength-bar mt-2">
              <div class="strength-label">{{ passwordStrength.label }}</div>
              <div class="progress">
                <div class="progress-bar" [ngClass]="passwordStrength.class" [style.width]="passwordStrength.width"></div>
              </div>
            </div>
          </div>
          <div class="form-group">
            <div class="form-icon">
              <i class="far fa-key"></i>
              <input [type]="showPassword ? 'text' : 'password'" formControlName="confirmPassword" class="form-control" placeholder="Confirm Password" (blur)="validateField('confirmPassword')" />
              <span class="password-view" (click)="togglePasswordVisibility()">
                <i [class]="showPassword ? 'far fa-eye' : 'far fa-eye-slash'"></i>
              </span>
            </div>
          </div>
          <div class="form-group">
            <div class="form-icon">
              <i class="far fa-calendar"></i>
              <input type="date" formControlName="dateNaissance" class="form-control" placeholder="Date of Birth" (blur)="validateField('dateNaissance')" />
            </div>
          </div>

          <div class="auth-btn">
            <button type="submit" class="theme-btn" [disabled]="isLoading">
              <span class="far fa-paper-plane"></span> Register
            </button>
          </div>
        </form>
        <div class="auth-bottom">
          <div class="auth-social">
            <p>Continue with social media</p>
            <div class="auth-social-list">
              <a href="#"><i class="fab fa-facebook-f"></i></a>
              <a href="#"><i class="fab fa-google"></i></a>
              <a href="#"><i class="fab fa-x-twitter"></i></a>
            </div>
          </div>
          <p class="auth-bottom-text">
            Already have an account? <a routerLink="/login">Login.</a>
          </p>
        </div>
      </div>
    </div>
  </div>
</div>
